class Solution:
    def findContentChildren(self, g, s):
        # Independent: match the greediest children against the biggest cookies,
        # iterating from the largest end instead of the smallest.
        gs = sorted(g, reverse=True)
        ss = sorted(s, reverse=True)
        count = 0
        j = 0
        for greed in gs:
            if j < len(ss) and ss[j] >= greed:
                count += 1
                j += 1
        return count

